css:
.loader {
  display: inline-flex;
  align-items: end;
  gap: 6px;
  height: 56px;
  color: #6366f1;
}
.loader span {
  width: 9px;
  height: 18px;
  border-radius: 999px;
  background: currentColor;
  animation: equalize 0.75s ease-in-out infinite;
}
.loader span:nth-child(2) { animation-delay: 0.12s; }
.loader span:nth-child(3) { animation-delay: 0.24s; }
.loader span:nth-child(4) { animation-delay: 0.36s; }
@keyframes equalize {
  0%, 100% { height: 18px; opacity: 0.45; }
  50% { height: 52px; opacity: 1; }
}
